+    fn test_check_status_serialization() {
+        let pass = serde_json::to_string(&CheckStatus::Pass).unwrap();
+        assert_eq!(pass, "\"pass\"");
+
+        let fail = serde_json::to_string(&CheckStatus::Fail).unwrap();
+        assert_eq!(fail, "\"fail\"");
+    }
